  '75828072-8f91-40f0-9f95-c54126eb166b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Config — Zero-Config Defaults vs. Explicit vite.config.ts$escape$,
  $escape$Vite works out of the box for React/Vue projects with zero configuration — `vite dev` infers entry point from `index.html`, serves from project root, and applies framework plugins automatically when detected. But the moment you need path aliases, custom build targets, or proxy rules, you drop a `vite.config.ts` at the project root and Vite picks it up automatically via its config resolution order (`vite.config.ts` → `.js` → `.mjs` → `.cjs`).

The config file exports a `UserConfig` object via `defineConfig()` — a typed wrapper that gives you IntelliSense without a separate tsconfig. Key top-level fields: `root` (defaults to `process.cwd()`), `base` (public path, defaults to `/`), `plugins`, `resolve.alias`, `server` (devserver options), and `build` (Rollup passthrough). The `build.rollupOptions` field gives you direct access to Rollup's input/output config for multi-page apps or library mode (`build.lib`). Splitting concerns across `vite.config.base.ts` and environment-specific files is common — merge them with `mergeConfig()` from `vite`.$escape$,
  $escape$// vite.config.ts
import { defineConfig, mergeConfig } from 'vite'
import react from '@vitejs/plugin-react'
import path from 'path'

export default defineConfig({
  plugins: [react()],
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
    },
  },
  server: {
    port: 3000,
    proxy: {
      '/api': 'http://localhost:5000',
    },
  },
  build: {
    rollupOptions: {
      output: { manualChunks: { vendor: ['react', 'react-dom'] } },
    },
  },
})$escape$,
  $escape$typescript$escape$,
