INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b0dab099-d175-42ca-9fd5-49b121ef2a29',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Dev Server — HMR, Proxy Setup, and HTTPS in Dev$escape$,
  $escape$Vite's dev server runs on native ESM, making HMR near-instant — only the changed module and its dependents are re-evaluated, not the full bundle. HMR is enabled by default; you can fine-tune it via `import.meta.hot` to register custom handlers and prevent full-page reloads when state matters.

For API proxying, `server.proxy` in `vite.config.ts` forwards matching paths to your backend. Use `changeOrigin: true` when your backend checks the `Host` header, and `rewrite` to strip path prefixes before forwarding.

For HTTPS in dev — essential when testing secure cookies, HSTS, or WebAuthn — set `server.https: true`. Vite uses `@vitejs/plugin-basic-ssl` for a self-signed cert, or pass a custom `key`/`cert` pair for a trusted local CA (e.g. from `mkcert`). Pair with `server.host: true` to expose on your LAN for device testing.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite';
import basicSsl from '@vitejs/plugin-basic-ssl';

export default defineConfig({
  plugins: [basicSsl()],
  server: {
    https: true,
    host: true,
    proxy: {
      '/api': {
        target: 'http://localhost:5000',
        changeOrigin: true,
        rewrite: (path) => path.replace(/^\/api/, ''),
      },
    },
  },
});$escape$,
