INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e0357be6-b847-4d14-bada-69bc702e6d8a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Path Aliases — Clean Imports with @ and resolve.alias$escape$,
  $escape$Vite's `resolve.alias` in `vite.config.ts` lets you replace deep relative imports with short, memorable prefixes. The canonical pattern maps `@` to your `src` directory, but you can define as many aliases as your project needs — `@components`, `@hooks`, `@lib`, etc.

Under the hood, Vite passes aliases to Rollup's resolver during build and to its dev-server module graph at runtime — so the same config works in both modes without extra plugins.

One gotcha: TypeScript doesn't know about Vite aliases. You must mirror every alias in `tsconfig.json` under `compilerOptions.paths`, or imports will typecheck as missing modules. The `vite-tsconfig-paths` plugin automates this by reading `tsconfig.json` directly so you maintain a single source of truth.

For monorepos, `resolve.alias` also accepts a function `(id) => string | undefined`, letting you dynamically redirect workspace package imports to local source files instead of built dist artifacts — critical for fast HMR across packages.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite';
import { resolve } from 'path';
import tsconfigPaths from 'vite-tsconfig-paths';

export default defineConfig({
  plugins: [tsconfigPaths()],
  resolve: {
    alias: {
      '@': resolve(__dirname, 'src'),
      '@components': resolve(__dirname, 'src/components'),
      '@lib': resolve(__dirname, 'src/lib'),
    },
  },
});

// tsconfig.json — must mirror aliases
// "paths": { "@/*": ["src/*"], "@components/*": ["src/components/*"] }$escape$,
  $escape$typescript$escape$,
