INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '77ddf9db-8640-4a8a-893b-cb844b321a30',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite's Dependency Pre-Bundling — Why Your First Dev Start Is Slow (And Every Restart Isn't)$escape$,
  $escape$Vite splits build work into two phases: pre-bundling bare module imports using esbuild, and serving your own source files as native ESM. The first `vite dev` run scans your entry points, bundles all `node_modules` dependencies into single ESM chunks under `node_modules/.vite/deps/`, and writes a metadata hash. Every subsequent start checks that hash — if your `package.json`, lockfile, or `vite.config.ts` hasn't changed, the cache is reused and pre-bundling is skipped entirely.

To force a full re-bundle without deleting the cache manually, run `vite --force`. To pre-bundle specific packages that Vite misses (e.g. CJS-heavy transitive deps), use `optimizeDeps.include`. Conversely, packages that Vite incorrectly bundles together can be excluded via `optimizeDeps.exclude`.

For build performance in production, `build.rollupOptions.output.manualChunks` lets you split vendor code deliberately, reducing re-bundling across deploys when only app code changes — Rollup's cache invalidation is hash-based per chunk.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite'

export default defineConfig({
  optimizeDeps: {
    include: ['lodash-es', 'some-cjs-package'],
    exclude: ['@my-org/local-pkg'],
  },
  build: {
    rollupOptions: {
      output: {
        manualChunks: {
          vendor: ['react', 'react-dom'],
          utils: ['lodash-es', 'date-fns'],
        },
      },
    },
  },
})$escape$,
