INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5c1ade21-2df9-4340-85c2-a480704c2b3a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Production Optimization — Minification, Compression, and Tree-Shaking$escape$,
  $escape$Vite uses esbuild for minification by default (`build.minify: 'esbuild'`), which is fast but skips some advanced optimizations. Switch to `'terser'` for deeper compression — it handles complex patterns esbuild won't touch, at the cost of slower builds. For compression, Vite doesn't serve gzip/brotli directly — that's your static server's job — but `vite-plugin-compression` generates `.gz` and `.br` artifacts at build time so Nginx or a CDN can serve them with zero runtime overhead.

Tree-shaking is automatic via Rollup, but it only eliminates truly unreferenced ESM exports. Side-effectful imports survive unless you mark your package `"sideEffects": false` in `package.json`. For library code, use `build.lib` mode with `formats: ['es']` to produce a pure ESM bundle that downstream bundlers can tree-shake. You can also use `build.rollupOptions.treeshake` to tune granularity — set `preset: 'safest'` for aggressive elimination or `'recommended'` for a balanced default. Use `rollup-plugin-visualizer` to audit what actually ships.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite'
import compression from 'vite-plugin-compression'
import { visualizer } from 'rollup-plugin-visualizer'

export default defineConfig({
  plugins: [
    compression({ algorithm: 'brotliCompress', ext: '.br' }),
    compression({ algorithm: 'gzip', ext: '.gz' }),
    visualizer({ open: true, gzipSize: true }),
  ],
  build: {
    minify: 'terser',
    terserOptions: { compress: { drop_console: true, passes: 2 } },
    rollupOptions: {
      treeshake: { preset: 'recommended' },
    },
  },
})$escape$,
