INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b44a1ad7-a57c-4c4a-a183-39a8df0acf42',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Plugin System — How Plugins Extend the Build Pipeline$escape$,
  $escape$Vite's plugin system is a superset of Rollup's, meaning any Rollup plugin works in Vite with minimal changes. Plugins are plain objects exposing lifecycle hooks — Vite adds its own hooks on top for dev-server-specific behavior.

Two categories matter: **universal hooks** (run during both dev and build) like `transform`, `resolveId`, and `load`; and **Vite-specific hooks** like `configureServer`, `transformIndexHtml`, and `handleHotUpdate`. The `enforce` property controls ordering — `'pre'` runs before Vite core plugins, `'post'` runs after.

The `transform` hook is the workhorse: it receives a module's code and id, and returns transformed code plus an optional source map. Vite pipes every imported module through the plugin chain in order. `resolveId` lets you intercept bare specifiers and redirect them to virtual modules — pair it with `load` to serve synthetic content. `configureServer` gives you direct access to the Vite dev server's Connect middleware stack, useful for injecting custom HTTP routes or WebSocket handlers during development.$escape$,
  $escape$// vite.config.ts
import type { Plugin } from 'vite'

function envInjectPlugin(): Plugin {
  const virtualId = 'virtual:env'
  const resolvedId = '\0' + virtualId

  return {
    name: 'env-inject',
    enforce: 'pre',
    resolveId(id) {
      if (id === virtualId) return resolvedId
    },
    load(id) {
      if (id === resolvedId) {
        return `export const BUILD_TIME = '${new Date().toISOString()}'`
      }
    },
  }
}

export default { plugins: [envInjectPlugin()] }$escape$,
  $escape$typescript$escape$,
