INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0c22c753-0301-470d-9199-f6f2709ce200',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Config Sharing — Extend Base Configs Across Monorepos and Speed Up CI$escape$,
  $escape$Vite has no built-in `extends` like TSConfig, but `mergeConfig` from `vite` gives you composable, type-safe config inheritance. Define a `vite.base.config.ts` at your repo root with shared plugins (e.g. `@vitejs/plugin-react`, `vite-tsconfig-paths`) and resolve aliases. Each package then imports and merges it, overriding only what differs — `build.outDir`, `server.port`, test globals, etc.

For CI caching, Vite's Rollup-based build writes chunks to `dist/assets`. Cache that directory keyed on a hash of `vite.config.ts`, `package-lock.json`, and your source files. On GitHub Actions, use `actions/cache` with a restore key fallback so a partial cache hit still avoids re-downloading node_modules. Vite's `build.manifest: true` emits `dist/.vite/manifest.json` — commit its hash as a cache buster instead of timestamps.

Depcheck `optimizeDeps.include` in your base config: pre-bundled deps are written to `node_modules/.vite/deps` and reused across runs if the lockfile hash matches, cutting cold-start times from ~4 s to under 500 ms in large apps.$escape$,
  $escape$// packages/shared/vite.base.config.ts
import { defineConfig, mergeConfig } from 'vite'
import react from '@vitejs/plugin-react'
import tsconfigPaths from 'vite-tsconfig-paths'

export const baseConfig = defineConfig({
  plugins: [react(), tsconfigPaths()],
  optimizeDeps: { include: ['react', 'react-dom', 'clsx'] },
  build: { manifest: true, sourcemap: true },
})

// apps/dashboard/vite.config.ts
import { mergeConfig } from 'vite'
import { baseConfig } from '../../packages/shared/vite.base.config'

export default mergeConfig(baseConfig, {
  build: { outDir: 'dist/dashboard' },
  server: { port: 5174 },
})$escape$,
